import type { Overwrite } from '~/types/overwrite.js'

type Overwriter = <OBJECT_A extends object, OBJECT_B extends object>(
  objectA: OBJECT_A,
  objectB: OBJECT_B
) => Overwrite<OBJECT_A, OBJECT_B>

export const overwrite: Overwriter = <OBJECT_A extends object, OBJECT_B extends object>(
  objectA: OBJECT_A,
  objectB: OBJECT_B
) => ({ ...objectA, ...objectB }) as Overwrite<OBJECT_A, OBJECT_B>
import type { ComputeObject } from './computeObject.js'

/**
 * Update the fields of `OBJECT_A` with the ones of `OBJECT_B`
 */
export type Overwrite<OBJECT_A extends object, OBJECT_B extends object> = ComputeObject<{
  [KEY in keyof OBJECT_A | keyof OBJECT_B]: KEY extends keyof OBJECT_B
    ? OBJECT_B[KEY]
    : KEY extends keyof OBJECT_A
      ? OBJECT_A[KEY]
      : never
}>

