import { isObject } from '~/utils/validation/isObject.js'

interface ExistsCondition {
  attr: string
  exists: true
}

/**
 * Walks a parsed put/update value alongside its schema to find `requiredIf` clauses whose
 * controlling attribute is set to a trigger value while their dependent attribute is absent
 * from the input, and returns the `attribute_exists` conditions needed to enforce them at
 * the database level (used for UPDATE commands, where the dependent may already be stored).
 */
export const collectRequiredIfConditions = (
  schema: MapSchema | ItemSchema,
  parsedValue: Record<string, unknown>,
  path: string[] = []
): ExistsCondition[] => {
  const conditions: ExistsCondition[] = []

  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
    const { requiredIf = [] } = attribute.props

    if (parsedValue[attributeName] === undefined) {
      for (const { attribute: controllingAttributeName, values } of requiredIf) {
        const controllingValue = parsedValue[controllingAttributeName]

        if (controllingValue === undefined || !values.includes(controllingValue)) {
          continue
        }

        conditions.push({ attr: [...path, attributeName].join('.'), exists: true })
        break
      }
    }

    const nestedValue = parsedValue[attributeName]
    if ((attribute.type === 'map' || attribute.type === 'item') && isObject(nestedValue)) {
      conditions.push(
        ...collectRequiredIfConditions(attribute as MapSchema | ItemSchema, nestedValue, [
          ...path,
          attributeName
        ])
      )
    }
  }

  return conditions
}
